from core.firebase import get_db

EJERCICIOS_MAESTROS = [
    {
        "nombre": "Sentadilla (Squat)",
        "bodyPart": "piernas",
        "target": "gluteos, cuadriceps",
        "gifUrl": "https://media.giphy.com/media/v1.",
        "instrucciones": "Bajar la cadera manteniendo la espalda recta, luego subir controladamente."
    },
    {
        "nombre": "Press de Banca (Bench Press)",
        "bodyPart": "pecho",
        "target": "pectorales, triceps",
        "gifUrl": "https://media.giphy.com/media/v1.",
        "instrucciones": "Bajar la barra al pecho y empujar hacia arriba."
    },
    {
        "nombre": "Dominadas (Pull Ups)",
        "bodyPart": "espalda",
        "target": "dorsales",
        "gifUrl": "https://media.giphy.com/media/v1.",
        "instrucciones": "Colgarse de la barra y subir el mentón por encima de la misma."
    }
]

def seed():
    db = get_db()
    if not db:
        print("No se pudo conectar a la base de datos.")
        return
    
    col = db.collection("biblioteca_ejercicios")
    for ej in EJERCICIOS_MAESTROS:
        col.document(ej['nombre']).set(ej)
        print(f"Ejercicio cargado: {ej['nombre']}")

if __name__ == "__main__":
    seed()
